-- 1. 상점판매원 (id: 1765283323000982)
UPDATE jobs SET user_contributed_json = '{"way":"상점판매원은 별도의 학력 요건 없이 입직할 수 있는 직업이다.[1] 고등학교 졸업 이상의 학력이면 대부분의 상점에 지원 가능하며, 편의점·의류매장·식품점 등 업종에 따라 무경험자도 채용된다.[1] 취업 후에는 상품 지식과 고객 응대 스킬을 현장에서 습득하며 경력을 쌓는다.[2] 유통관리사 자격증을 취득하면 매장 관리직이나 바이어 등 상위 직무로 이동할 수 있다.[2] 백화점·대형마트·프랜차이즈 브랜드 등은 공개채용을 통해 정규직으로 입직하는 경로도 있다.[1]","overviewSalary":{"sal":"상점판매원의 평균 연봉은 약 2,500만 원 수준이다.[3] 대형 유통사 정규직은 3,000만 원 이상이며, 인센티브·성과급 구조를 갖춘 곳도 있다.[3]","source":"워크넷, 커리어넷(2024)"},"overviewProspect":{"main":"온라인 쇼핑 확대로 오프라인 상점 판매원 수요는 완만한 감소세를 보이고 있다.[4] 반면 체험형 쇼핑·프리미엄 매장·라이브커머스 등 새로운 판매 형태에서 전문 판매 인력 수요는 유지되고 있다.[4]","source":"고용노동부 직업전망(2024)"},"trivia":"세계 최대 소매 유통기업 월마트는 약 210만 명의 미국 내 직원 중 상당수가 매장 판매원이다.[5] 국내 편의점 점포 수는 2024년 기준 약 5만 6천 개를 넘어 일본보다 인구 대비 밀도가 높다.[5] 고객 응대 전문가 연구에 따르면, 매장 판매원의 첫인상과 목소리 톤이 구매 결정에 미치는 영향이 40% 이상이라는 분석도 있다.[5]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"주말·공휴일 근무가 빈번하고 장시간 서서 일하는 환경이다.[6] 교대 근무 체계가 있는 대형 유통사는 그나마 규칙적이지만, 소규모 상점은 업주 일정에 따른 불규칙 근무가 일반적이다.[6]","socialDetail":"매일 다양한 고객을 상대하며 소통 능력이 자연스럽게 발달한다.[7] 팀워크 중심의 매장 운영으로 동료 간 협업이 활발하나, 감정 노동 스트레스가 수반된다.[7]"},"detailReady":{"curriculum":["유통·판매 관련 전공(유통학과, 경영학과) 이수","고객서비스·커뮤니케이션 교육 이수","POS 시스템 조작법 및 재고관리 실습","상품 MD 지식·VMD(비주얼 머천다이징) 기초 학습"],"recruit":["대형마트·백화점 공개채용 (롯데·현대·신세계 등)","편의점·프랜차이즈 점포 아르바이트 후 정규직 전환","고용노동부 워크넷 소매업 채용공고 지원"],"training":["유통관리사 2급·1급 취득으로 관리직 진출","CS Leaders 관리사 자격으로 고객관리 전문성 강화","판매사 자격 취득","라이브커머스·온라인 판매 병행으로 역량 확장"]},"sidebarJobs":["노점 및 이동판매원","방문판매원","상품대여원","온라인판매원","주유원","통신기기·서비스판매원"],"sidebarMajors":["경영학과","유통학과","마케팅경영과","서비스유통과","무역·유통학과","경영정보학과"],"sidebarCerts":["유통관리사","CS Leaders 관리사","판매사","전자상거래관리사","소비자전문상담사"],"heroTags":["상점판매원","소매판매","유통업","고객서비스","매장관리","판매직","유통관리사"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"워크넷 직업정보 - 상점판매원","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"},{"id":2,"text":"커리어넷 직업백과 - 판매원","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewSalary.sal":[{"id":3,"text":"워크넷 임금직업정보(2024)","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"overviewProspect.main":[{"id":4,"text":"고용노동부 직업전망(2024)","url":"https://www.moel.go.kr/"}],"trivia":[{"id":5,"text":"통계청 유통업 통계, 커리어넷","url":"https://kostat.go.kr/"}],"detailWlb.wlbDetail":[{"id":6,"text":"워크넷 직업정보 근무환경","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"detailWlb.socialDetail":[{"id":7,"text":"커리어넷 직업 만족도 조사","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283323000982';

-- 2. 조경원 (id: 1765283373057723)
UPDATE jobs SET user_contributed_json = '{"way":"조경원이 되기 위한 공식 학력 요건은 없으며, 관련 직업훈련이나 현장 경험으로도 입직이 가능하다.[1] 전문대 또는 대학교 조경학과·원예학과를 졸업하면 조경회사·공공기관 취업에 유리하다.[1] 조경기사 자격증을 취득하면 공공공사 입찰 등 제도적 혜택이 있어 커리어 성장에 크게 도움이 된다.[2] 공원관리공단·지방자치단체 조경직 공무원 시험을 준비하는 경로도 있다.[2] 실력 있는 조경원은 조경설계사무소나 독립 정원사로 전환하기도 한다.[1]","overviewSalary":{"sal":"조경원의 평균 연봉은 약 2,800만 원 수준이다.[3] 조경기사 자격 보유자나 공무원 조경직은 3,500만 원 이상의 급여를 받기도 한다.[3]","source":"워크넷, 커리어넷(2024)"},"overviewProspect":{"main":"도시 녹지 조성 정책 강화와 기후변화 대응 수요 증가로 조경 분야의 고용 전망은 보통 수준을 유지하고 있다.[4] 생태조경·스마트가든·옥상녹화 등 신규 영역이 확대되며 전문 인력 수요도 꾸준하다.[4]","source":"고용노동부 직업전망(2024)"},"trivia":"국내 도시공원 면적은 2020년 기준 약 8만 ha에 달하며, 이를 유지·관리하는 조경원의 역할이 크다.[5] 일본에서는 정원사를 전통 예인으로 대우하며, 30년 이상 수련한 명인 정원사에게 특별한 칭호를 부여한다.[5] 옥상 정원 1㎡는 연간 약 5.9kg의 이산화탄소를 흡수해 도시 열섬현상 완화에 기여한다는 연구 결과가 있다.[5]","detailWlb":{"wlb":"보통이하","social":"보통이하","wlbDetail":"야외 현장 작업 특성상 혹서기·혹한기에도 작업이 이어지며, 체력 소모가 크다.[6] 공사 일정에 따른 계절성 업무 편중(봄·가을 집중)이 있으며, 기상 조건에 영향을 크게 받는다.[6]","socialDetail":"자연 속에서 일하는 만족감이 크지만, 비교적 단독 작업 비중이 높아 대인관계 폭은 좁은 편이다.[7] 공공기관이나 대형 조경사무소 소속의 경우 팀 단위 협업 환경이 갖춰지기도 한다.[7]"},"detailReady":{"curriculum":["조경학과·원예학과·산림자원학과 전공 이수","조경설계 CAD·BIM 소프트웨어 실습","식물 수목 감별·병해충 관리 이론 학습","토목·포장·배수 설계 기초 습득"],"recruit":["조경회사·조경설계사무소 신입 채용 지원","지방자치단체 조경직 공무원 시험 응시","공원관리공단 공채 지원 (서울시설공단 등)"],"training":["조경기사·조경산업기사 취득 (경력 상향 필수)","식물보호기사 자격으로 전문성 강화","자연환경관리기술사 취득으로 상위 직무 진출","정원 설계 관련 해외 연수 및 자격 취득"]},"sidebarJobs":["조경사","곡식작물재배자","과수작물재배자","국가유산수리조경공","육묘 및 화훼작물재배자","채소·특용작물재배원"],"sidebarMajors":["조경학과","조경과","원예학과","원예과","산림자원학과","환경디자인과"],"sidebarCerts":["조경기사","조경산업기사","식물보호기사","자연환경관리기술사","조경기능사"],"heroTags":["조경원","조경","정원관리","녹지관리","조경기사","도시녹화","식물관리"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 - 조경원","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보 - 조경","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"overviewSalary.sal":[{"id":3,"text":"워크넷 임금직업정보(2024)","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"overviewProspect.main":[{"id":4,"text":"고용노동부 직업전망(2024)","url":"https://www.moel.go.kr/"}],"trivia":[{"id":5,"text":"국토교통부 도시공원 통계, 커리어넷","url":"https://www.molit.go.kr/"}],"detailWlb.wlbDetail":[{"id":6,"text":"워크넷 직업정보 근무환경","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"detailWlb.socialDetail":[{"id":7,"text":"커리어넷 직업 만족도 조사","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283373057723';

-- 3. 출판물기획자 (id: 1765283467631283)
UPDATE jobs SET user_contributed_json = '{"way":"출판물기획자가 되는 가장 일반적인 경로는 출판사 편집부에 입사해 편집자 경험을 쌓은 뒤 기획직으로 전환하는 것이다.[1] 국어국문학·문예창작·문화콘텐츠 관련 학과 졸업 후 출판사에 신입 공채 또는 인턴십으로 입사하는 방법이 주된 진입 루트다.[1] 일부 출판사는 기획자를 경력직으로만 채용하므로, 처음에는 편집자·교정교열 등으로 경험을 쌓는 것이 현실적이다.[2] 작가 발굴·원고 개발·시장 분석·마케팅 협업까지 종합적인 역량이 필요하므로 도서 트렌드와 독자 데이터 분석 능력도 중요하다.[2]","overviewSalary":{"sal":"출판물기획자의 평균 연봉은 약 3,200만 원 수준이며, 대형 출판사 수석 기획자는 5,000만 원 이상을 받기도 한다.[3] 프리랜서 기획자는 계약 건별 수수료 방식으로 수입이 불규칙할 수 있다.[3]","source":"커리어넷, 워크넷(2024)"},"overviewProspect":{"main":"전자책·웹툰·오디오북 등 새로운 콘텐츠 형식의 등장으로 출판 기획 영역이 디지털 전반으로 확대되고 있다.[4] 단순 종이책 출판은 정체 수준이지만, IP 중심의 콘텐츠 기획 역량을 갖춘 인재 수요는 꾸준히 증가세다.[4]","source":"한국출판문화산업진흥원, 고용노동부(2024)"},"trivia":"국내 출판 시장에서 단 한 권의 베스트셀러가 출판사 연간 수익의 50% 이상을 차지하는 경우도 있어, 기획자의 안목이 회사 명운을 좌우한다.[5] 세계적 베스트셀러 해리포터는 12개 출판사에서 거절당한 후 13번째 시도에서 채택됐고, 이 결정을 내린 기획자의 판단이 역사적 성공으로 이어졌다.[5] 국내 출판사 수는 2만 개 이상이지만 연 매출 10억 원 이상의 기업은 약 300곳 미만이라, 기획자의 활동 무대는 소수의 중대형 출판사에 집중된다.[5]","detailWlb":{"wlb":"보통","social":"보통이상","wlbDetail":"출판 시즌(연초·추석 전후)에는 마감 집중으로 야근이 생기지만, 평상시에는 비교적 규칙적인 업무 패턴을 유지한다.[6] 재택·유연근무제를 도입한 출판사가 늘어나 워라밸이 개선되는 추세다.[6]","socialDetail":"작가·디자이너·인쇄소·마케터 등 다양한 직군과 협업하며 폭넓은 네트워크를 형성한다.[7] 독서 모임·출판 커뮤니티 등 지적 자극이 많은 사회적 환경에서 일하게 된다.[7]"},"detailReady":{"curriculum":["국어국문학·문예창작·문화콘텐츠학과 전공 이수","교정·교열 기초 및 편집 디자인 툴 학습","도서 시장 트렌드 분석·서평 글쓰기 훈련","저작권법·출판계약 관련 법률 기초 학습"],"recruit":["대형 출판사(민음사·문학동네·위즈덤하우스 등) 편집부 공채","중소 출판사 편집 인턴십 후 정규직 전환","한국출판문화산업진흥원 취업 지원 프로그램 활용"],"training":["출판기획편집사 자격증 취득","콘텐츠 IP 기획 역량 강화를 위한 웹툰·웹소설 플랫폼 스터디","해외 판권 거래(에이전시) 경험으로 글로벌 기획 역량 개발","작가 매니지먼트·북 에이전트 업무 경험 축적"]},"sidebarJobs":["방송작가","번역가","소설가","영화시나리오작가","출판물검수원","출판물편집자","통역가","출판물기획전문가"],"sidebarMajors":["국어·국문학과","문예창작학과","문화콘텐츠학과","미디어출판과","광고·홍보학과","미디어학과"],"sidebarCerts":["출판기획편집사","교정사","독서지도사","GTQ(그래픽기술자격)","저작권관리사"],"heroTags":["출판기획자","출판사","편집기획","도서기획","콘텐츠기획","출판편집","북에디터"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 - 출판물기획자","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"overviewSalary.sal":[{"id":3,"text":"커리어넷 임금정보(2024)","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewProspect.main":[{"id":4,"text":"한국출판문화산업진흥원 출판산업 동향(2024)","url":"https://www.kpipa.or.kr/"}],"trivia":[{"id":5,"text":"한국출판문화산업진흥원, 워크넷","url":"https://www.kpipa.or.kr/"}],"detailWlb.wlbDetail":[{"id":6,"text":"커리어넷 직업 근무환경 정보","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"detailWlb.socialDetail":[{"id":7,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}]}}' WHERE id = '1765283467631283';

-- 4. 증권·외환딜러 (id: 176528342701427)
UPDATE jobs SET user_contributed_json = '{"way":"증권·외환딜러가 되려면 경영·경제·수학 관련 학과 졸업 후 증권사·은행·외국계 금융기관에 입사하는 경로가 일반적이다.[1] 공개채용 시 금융 관련 자격증(증권투자권유대행인, 파생상품투자권유자문인력 등)이 있으면 가산점이 주어지는 경우가 많다.[1] 입사 후 트레이딩룸 배치를 받기 위해서는 내부 심사와 금융투자협회 등록 절차를 거쳐야 한다.[2] 영어 실력과 수리적 분석 능력이 매우 중요하며, CFA·FRM 등 글로벌 자격증 취득이 커리어 경쟁력을 크게 높인다.[2]","overviewSalary":{"sal":"증권·외환딜러의 평균 연봉은 약 6,000만 원~1억 원 수준이다.[3] 외국계 투자은행 소속 딜러는 성과 보너스 포함 시 수억 원 이상을 받기도 한다.[3]","source":"워크넷, 커리어넷(2024)"},"overviewProspect":{"main":"알고리즘 트레이딩과 AI의 확산으로 단순 호가 매칭 역할은 자동화되는 추세지만, 복잡한 외환 헤지·파생상품 전략 수립 역할은 여전히 전문 딜러의 몫이다.[4] 글로벌 금융시장 변동성이 높아질수록 리스크 관리 전문 딜러의 수요는 유지된다.[4]","source":"고용노동부 직업전망, 금융투자협회(2024)"},"trivia":"외환 시장(Forex)은 하루 거래대금이 약 7조 5천억 달러로 세계에서 가장 큰 금융시장이다.[5] 유명 외환딜러 닉 리슨은 1995년 베어링은행을 단독으로 파산시킨 역사적 사례로 딜러의 리스크 관리가 얼마나 중요한지를 보여줬다.[5] 국내 증권사 트레이딩룸은 보통 새벽 6시에 개장해 야간 선물 시장까지 대응하는 경우도 있어 체력 관리가 필수다.[5]","detailWlb":{"wlb":"낮음","social":"보통이하","wlbDetail":"글로벌 시장 개장 시간에 맞춰 새벽 출근이 일상화되어 있으며, 시장 급변 시 퇴근이 지연된다.[6] 성과 압박과 고강도 집중력이 요구되어 번아웃 위험이 높고, 워라밸은 금융업 중에서도 하위권에 속한다.[6]","socialDetail":"트레이딩룸 내 소수 팀원과의 밀접한 협업이 이루어지지만, 경쟁적 문화로 인해 사내 인간관계는 단순한 편이다.[7] 글로벌 거래 상대방·브로커와의 네트워크는 폭넓다.[7]"},"detailReady":{"curriculum":["경제학·경영학·수학·금융공학 전공 이수","파생상품·외환 이론 및 리스크 관리 학습","Bloomberg Terminal·Reuters Eikon 실습","계량분석·통계 프로그래밍(Python, R) 역량 강화"],"recruit":["국내 대형 증권사(미래에셋·삼성·한투 등) 공채 트레이딩 부문 지원","외국계 투자은행(골드만삭스·JP모건 등) 인턴십 지원","은행 외환 딜링 부문 신입 공채 지원"],"training":["증권투자권유대행인·파생상품투자권유자문인력 등록 필수","CFA(공인재무분석사) 취득으로 글로벌 경쟁력 강화","FRM(금융리스크관리사) 취득으로 리스크 전문성 입증","외환전문역 자격 취득"]},"sidebarJobs":["금융상품개발자","보험상품개발자","손해사정사","신용분석가","외환딜러","자산운용가","투자분석가"],"sidebarMajors":["경제학과","금융·보험학과","경영학과","금융경영과","수학과","국제통상학과"],"sidebarCerts":["증권투자권유대행인","파생상품투자권유자문인력","CFA","FRM","외환전문역"],"heroTags":["증권딜러","외환딜러","FX트레이딩","금융투자","자본시장","트레이더","파생상품"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 - 증권·외환딜러","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"overviewSalary.sal":[{"id":3,"text":"워크넷 임금직업정보(2024)","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"overviewProspect.main":[{"id":4,"text":"고용노동부 직업전망, 금융투자협회(2024)","url":"https://www.moel.go.kr/"}],"trivia":[{"id":5,"text":"BIS 외환시장 통계, 워크넷","url":"https://www.bis.org/statistics/rpfx22.htm"}],"detailWlb.wlbDetail":[{"id":6,"text":"워크넷 직업정보 근무환경","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"detailWlb.socialDetail":[{"id":7,"text":"커리어넷 직업 만족도 조사","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '176528342701427';

-- 5. 방송송출장비기사 (id: 1765283439371599)
UPDATE jobs SET user_contributed_json = '{"way":"방송송출장비기사가 되려면 전기·전자·방송 관련 학과를 졸업한 뒤 방송사·케이블사·IPTV 사업자 등에 기술직으로 입사하는 경로가 일반적이다.[1] 전문대 방송영상과·전기전자과 졸업자도 지원 가능하며, 방송통신기사·무선설비기사 등 국가기술자격증이 있으면 취업에 유리하다.[1] 방송사 공채 기술직 또는 방송 장비 제조·유지보수 업체를 통해 입직하는 방법도 있다.[2] 현장에서는 디지털 방송 장비·IP 기반 송출 시스템·위성 장비 등 최신 기술을 지속적으로 습득해야 한다.[2]","overviewSalary":{"sal":"방송송출장비기사의 평균 연봉은 약 3,500만~4,500만 원 수준이다.[3] 지상파 방송사 소속은 5,000만 원 이상이며, 교대 근무 수당 등 부가급여가 별도로 지급된다.[3]","source":"워크넷, 커리어넷(2024)"},"overviewProspect":{"main":"디지털 전환과 IP 기반 방송 인프라 확대로 방송 기술 인력 수요는 안정적으로 유지되고 있다.[4] OTT 플랫폼 성장에 따라 스트리밍 송출 기술 전문가 수요가 새롭게 창출되는 추세다.[4]","source":"고용노동부 직업전망, 방송통신위원회(2024)"},"trivia":"현대 지상파 방송은 방송 신호가 스튜디오를 떠나 안방에 도달하기까지 수십 개의 장비를 0.1초 미만의 지연으로 통과한다.[5] 생방송 중 단 1초의 송출 오류도 수십만 시청자에게 영향을 미치기 때문에, 송출기사는 365일 24시간 교대 모니터링 체제를 유지한다.[5] UHD 방송 도입 이후 방송 데이터 용량이 HD 대비 4배 이상 증가해 장비 관리의 기술적 복잡도가 크게 높아졌다.[5]","detailWlb":{"wlb":"보통이하","social":"보통이하","wlbDetail":"24시간 365일 방송 송출을 유지해야 하므로 야간·주말·공휴일 교대 근무가 필수적이다.[6] 방송 사고 발생 시 즉각 대응해야 하는 긴장감이 상시 수반되며, 명절에도 당직 근무가 있다.[6]","socialDetail":"방송 기술팀 내부 팀원과의 긴밀한 협업이 이루어지지만, 기술직 특성상 대외 네트워크 형성 기회는 상대적으로 적다.[7] 방송사 내 다른 부서(편성·제작 등)와의 접점은 주로 송출 관련 기술 지원으로 한정된다.[7]"},"detailReady":{"curriculum":["전기전자공학·방송공학·정보통신공학 전공 이수","디지털 방송 시스템(DVB-T, ATSC) 이론 학습","IP 기반 방송 인프라 및 네트워크 기초 실습","방송 장비 운영·유지보수 현장 실습"],"recruit":["지상파 방송사(KBS·MBC·SBS 등) 기술직 공채 지원","케이블방송사·IPTV 사업자 기술 채용 지원","방송 장비 제조·유지보수 전문업체 입사"],"training":["방송통신기사·무선설비기사 국가기술자격 취득","정보통신기사·전파통신기사 취득으로 전문성 확장","Cisco CCNA 등 네트워크 자격으로 IP 송출 기술 강화","방송통신위원회 기술 교육과정 이수"]},"sidebarJobs":["공정장비기획사무원","반도체장비기구개발자","반도체장비기구조립원","방송송출기사","유무선방송설비기사","통신장비기사"],"sidebarMajors":["전기전자공학과","전자공학과","방송영상과","정보·통신공학과","신문방송학과","전기공학과"],"sidebarCerts":["방송통신기사","무선설비기사","정보통신기사","전파통신기사","전자기기기능사"],"heroTags":["방송송출","방송기술","송출기사","방송장비","디지털방송","방송통신기사","OTT송출"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 - 방송송출장비기사","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"overviewSalary.sal":[{"id":3,"text":"워크넷 임금직업정보(2024)","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"overviewProspect.main":[{"id":4,"text":"고용노동부 직업전망, 방송통신위원회(2024)","url":"https://www.moel.go.kr/"}],"trivia":[{"id":5,"text":"방송통신위원회, 커리어넷 직업정보","url":"https://www.kcc.go.kr/"}],"detailWlb.wlbDetail":[{"id":6,"text":"워크넷 직업정보 근무환경","url":"https://www.work.go.kr/empInfo/jobInfo/jobInfoMain.do"}],"detailWlb.socialDetail":[{"id":7,"text":"커리어넷 직업 만족도 조사","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283439371599';
